import{o as e,c as m,C as p}from"./framework.5e85cea8.js";const t='{"title":"Глава 7","description":"","frontmatter":{"title":"Глава 7","subtitle":"Малини виджайоттара тантра","tags":"malini","date":"2020-09-30T00:00:00.000Z"},"relativePath":"texts/malini-vijayottara/7.md","lastUpdated":1624912825941}',a={},_=p("<p>Шива сказал:</p><p>Теперь поведаю о мудрах Шивы и Шакти, защитившись которыми, произносящий мантру (садхака) обретет все совершенства ..1.</p><p><em>Тришула, падма, шакти, чакра, ваджра, данда, дамштра, махапрета, махамудра, кхагаишвари, маходайа, карала, кхатванга, капалака, хала, паша, анкуша, гханта, мудгара, тришикха, авахана, стхапана, ниродха, дравьяда</em> и <em>нати</em> известны как бесчисленные йога мудры, о Почитаемая героями!.2-4.</p><p>Следует оттянуть указательный, средний и безымянный палец правой (руки), и соединить большой палец с мизинцем. Это именуется <em>тришула (мудрой</em>) ..5.</p><p>Сложив руки в форме лотоса, следует показать <em>падма мудру</em> ..6а.</p><p>Вытянутые (в падма мудре) пальцы следует направить внутрь, Средние пальцы (остаются) вытянуты. Это именуется <em>мудрой Кумари Шакти</em> ..6б-7а.</p><p>На тыльную сторону левого кулака кладется правый (<em>далее текст поврежден</em>).7.</p><p>Сверху тыльной стороны левой ладони кладется правая рука ладонью вниз (<em>текст поврежден</em>) ..8.</p><p>Разведя большой (палец) и мизинец (в стороны), оставшиеся (пальцы) направляются к запястью (сжимаются в кулак). Это именуется <em>лунной ваджра мудрой</em>, творящей удовлетворение ..9.</p><p>Следует поднять вверх правую руку с большим пальцем, зажатым в кулаке. Это именуется <em>данда мудрой</em>, Вивасватой, любимой Кулой ..10.</p><p>Развернув левый (и правый) кулаки к лицу, мизинцы отводятся в сторону от кулака. Это именуется, о Деви, <em>дамштра мудрой</em>, Чамундой, Радующей Кулу ..11.</p><p>На левое колено кладется стопа. На нее опускаются кисти. Взгляд не мигает, шея подогнута, язык высунут.(Эта мудра) любимая сонмом йогинов, именуется <em>Йогешвари</em>(Владычицей йоги) ..12-13а.</p><p>Пусть мудрый двигает руки (обращенные) ладонями вниз от стоп до сердца. Перед лицом они разводятся в стороны, вверху (над головой) их следует сложить вместе. Это именуется <em>маха мудрой</em>, используемой в обряде очищения тела. Она используется йогинами при всех обрядах ради успеха в йоге ..14- 15а.</p><p>Приняв позу связанного лотоса, следует поместить владыку чувств (язык) в небо. Вытянув тело (прямо) подобно палке следует быстро вести (Кундалини Шакти) через три пространства (<em>т.е. Шакти, вьяпини и самана,</em> <em>расположенных</em> <em>начиная с межбровия и заканчивая брахмарандхрой</em>). Приняв такую асану, великий йогин обретёт движение по небу. (<em>Так описана Кхечари мудра</em>) .15б-17а.</p><p>Следует соединить средний и безымянный палец левой руки с большим пальцем, мизинец и указательный с мизинцем и указательным пальцем (правой руки, у которой) средний и безыменный палец соединены с большим пальцем. Это именуется <em>маходая мудрой</em>, творящей для людей великое возникновение ..17б-19.</p><p>Мизинцами и безымянными пальцами следует оттянуть уголки губ и двигать языком (как бы) производя звук ХА-ХА. Эта страшная на вид <em>карала мудра</em> творит страх врагам ..20-21а.</p><p>(Следует сжать) левую руку в кулак, мизинец поднят вверх. Это именуется <em>кхатванга мудрой</em>, теперь выслушай о <em>капала (мудре)</em> ..21б-22а.</p><p>Правая ладонь (обращена) вниз, пальцы слегка соприкасаются. Это именуется <em>капала (мудрой)</em>, теперь услышь о <em>хала мудре</em> (мудра плуга) ..22б-23а.</p><p>Правой рукой зажатой в кулак следует охватить указательный палец левой руки (подобно) рту, это именуется <em>хала мудрой</em> (мудрой плуга) ..23-24а.</p><p>Правый и левый кулаки сжаты, оба указательных пальцев переплетены, кончик левого большого пальца соприкасается (с кончиком указательного пальца правой). Это именуется <em>паша мудрой</em>, ограничивающей распространение ..24б-25а.</p><p>Когда левый кулак при хала (мудрее) лишен правого (кулака), это (будет) <em>анкуша (мудра)</em>.25б.</p><p>Пусть мудрый просунет указательный палец правой руки (сверху), через середину пальцев (<em>между средним и безымянным пальцами</em>) левой, обращенной ладонью вниз. Это именуется благоприятной <em>гханта мудрой</em> (мудрой колокола) ..26.</p><p>Следует повернуть руки ладонями вверх, с пальцами, переплетенными друг с другом и направленными внутрь. Безымянные пальцы должен находится на тыльной стороне средних, указательные пальцы соединены с большими пальцами ..27.</p><p>Два средних пальца собраны вместе. Мизинцы и указательные пальцы отогнуты в стороны от средних пальцев. Это _мудгара _и <em>тришикха (известная так же, как йони)__(мудры)</em>, творящие мгновенно авешу ..28-29а.</p><p>Сложив руки в <em>анджали (мудру)</em>, пусть мудрый поднесет большие пальцы к основанию средних (пальцев). Эта <em>авахана (мудра</em> используется) с мантрой в ритуале (призывания) ..29б-30а.</p><p>Большие пальцы кладутся на кулаки - это именуется <em>стхапани (мудрой)</em> ..30б.</p><p>Оба больших пальца помещаются внутри (сведенных кулаков)- это известно как <em>саниродхини (мудра)</em>, именуемая также <em>дравьяда</em> (дающей богатство) ..31.</p><p>Следует сложить ладони с вытянутыми пальцами перед сердцем- это <em>намаскара мудра</em> (выполняется) при (произнесении) мантр и молитв ..32.</p><p>Пальцы (левой и правой руки) переплетаются друг с другом. Мизинец правой руки следует соединить с кончиком безымянного .33.</p><p>Левый указательный палец соединяется со средним пальцем правой (руки). Большие пальцы размещаются у основания средних пальцев. Эта <em>(амритакарана) мудра</em> являет амриту (<em>она же дхену мудра</em>) ..34.</p><p>У основания пупка помещается правая (рука) поверх левой. Большой и указательный пальцы соединены и обращены вверх при практике йоги (<em>дхьяна мудра</em>) ..35.</p><p>Это собрание мудр мудрец, произносящий мантру, должен выполнить в сердце. При выполнении всех их произносится: ОМ ХРИМ, имя (мудры), затем НАМАХ ..36. [small]Такова в священной «Малини виджайа тантре» седьмая глава (именуемая) «Глава о мудрах».[/small]</p>",32);a.render=function(p,t,a,r,i,l){return e(),m("div",null,[_])};export default a;export{t as __pageData};
